// -------- MOTOR TASK (core1) --------
void motorTask() {
    motor.foc_modulation   = FOCModulationType::SpaceVectorPWM;
    motor.torque_controller = TorqueControlType::voltage;
    motor.controller       = MotionControlType::angle;
    motor.voltage_sensor_align = MOTOR_VOLTAGE_SENSOR_ALIGN;
    motor.zero_electric_angle = MOTOR_ZERO_ELECT_ANGLE;
    motor.sensor_direction = Direction::CW;
    motor.voltage_limit = MOTOR_VOLTAGE_LIMIT;
    motor.velocity_limit = MOTOR_VELOCITY_LIMIT_HOME;

    motor.PID_velocity.P = PID_VELOCITY_P;
    motor.PID_velocity.I = PID_VELOCITY_I;

    motor.init();

    // Поиск нулевой позиции (концевик)
    float search_speed = HOMING_SPEED_BASE * MOTOR_SIDE_SIGN;
    while (digitalRead(18) == HIGH){
        motor.loopFOC();
        motor.move(search_speed);
        temp_angle = sensor.getAngle();
    }

    // Калибровка
    obnal(temp_angle);
    motor.move(ANGLE_MIN);
    motor.velocity_limit = MOTOR_VELOCITY_LIMIT_WORK;
    motor.init();

    // Основной цикл управления
    while (true) {
        motor.loopFOC();

        if (value_can_tangle != 0) {
            target_angle = mapDouble(value_can_tangle, PWM_MIN, PWM_MAX, ANGLE_MIN, ANGLE_MAX);
        } else {
            target_angle = ANGLE_MIN;
        }

        motor.move(target_angle);
    }
}

