static void cyphal_rx_callback(CanardRxTransfer* transfer) {
    if (transfer->metadata.port_id == PORT_ID_CMD_VEC31) {
        zubax_primitive_real16_Vector31_1_0 msg = {0};
        size_t inout_size = transfer->payload_size;

        if (zubax_primitive_real16_Vector31_1_0_deserialize_(
                &msg,
                (const uint8_t*)transfer->payload,
                &inout_size) >= 0) {

            value_can_tangle = msg.value[INDEX_SETPOINT];
        }
    }

    // Освобождение памяти
    o1heapFree(o1heap_get_instance(), transfer->payload);
}

static void can_rx_callback(struct can2040* cd, uint32_t notify, struct can2040_msg* msg) {
    if (notify & CAN2040_NOTIFY_RX) {
        uint32_t can_id = msg->id & 0x1FFFFFFF;

        CanardFrame frame = {
            .extended_can_id = can_id,
            .payload_size    = msg->dlc,
            .payload         = msg->data
        };

        CanardRxTransfer transfer;
        CanardRxSubscription* sub = nullptr;

        int8_t res = canardRxAccept(&canard, micros_now_cyp(), &frame, 0, &transfer, &sub);
        if (res > 0) {
            cyphal_rx_callback(&transfer);
        }
    }
}

