    def _create_value_widget(self, param: dict):
        ptype = param.get("type")
        value = param.get("value")

        if ptype == "int":
            spin = QtWidgets.QSpinBox()
            spin.setMaximum(999999)
            spin.setMinimum(-999999)
            spin.setValue(int(value))
            return spin
        elif ptype == "float":
            dspin = QtWidgets.QDoubleSpinBox()
            dspin.setDecimals(3)
            dspin.setMaximum(999999.0)
            dspin.setMinimum(-999999.0)
            dspin.setValue(float(value))
            return dspin
        elif ptype == "bool":
            chk = QtWidgets.QCheckBox()
            chk.setChecked(bool(value))
            return chk
        elif ptype == "color":
            btn = QtWidgets.QPushButton()
            col = QtGui.QColor(*value)
            btn.setStyleSheet(f"background-color: {col.name()}")
            btn.clicked.connect(lambda _, b=btn: self._choose_color(b))
            btn.setProperty("color_value", value)
            return btn
        else:
            edit = QtWidgets.QLineEdit(str(value))
            return edit

