    def check_gst(self) -> bool:
        """
        Проверяет наличие папки %APPDATA%/colibri/gst.
        Если папка отсутствует или пуста — создаёт её и загружает из Gitea.
        При любой ошибке полностью очищает папку.
        """
        try:
            appdata = os.getenv("APPDATA") or str(Path.home() / "AppData" / "Roaming")
            colibri_dir = Path(appdata) / "colibri"
            gst_dir = colibri_dir / "gst"
            print("Checking GST at", gst_dir)
            if gst_dir.exists() and any(gst_dir.iterdir()):
                try:
                    self.progress.emit(100, f"GST found at {gst_dir}")
                except Exception:
                    pass
                return True
            gst_dir.mkdir(parents=True, exist_ok=True)
            BASES = [
                "http://10.2.64.253:3000/api/v1/repos/RuslanYK/colibri_bin",
                "http://192.168.101.6:3000/api/v1/repos/RuslanYK/colibri_bin",
            ]
            BRANCH = "main"
            tmp_dir = gst_dir.parent / (gst_dir.name + "_tmp")
            shutil.rmtree(tmp_dir, ignore_errors=True)
            last_error = None
            for base in BASES:
                try:
                    tmp_dir.mkdir(parents=True, exist_ok=True)
                    download_dir(base, "gst", tmp_dir)
                    shutil.rmtree(gst_dir, ignore_errors=True)
                    shutil.move(str(tmp_dir), str(gst_dir))
                    try:
                        self.progress.emit(100, f"GST successfully loaded at {gst_dir} (from {base})")
                    except Exception:
                        pass
                    return True
                except Exception as e:
                    last_error = e
                    shutil.rmtree(tmp_dir, ignore_errors=True)
                    print(f"Failed to download from {base}: {e}")
                    continue
            shutil.rmtree(gst_dir, ignore_errors=True)
            try:
                self.progress.emit(0, f"Failed to load GST from all servers: {last_error}")
            except Exception:
                pass
            return False
        except Exception as e:
            try:
                self.progress.emit(0, f"Critical error in check_gst: {e}")
            except Exception:
                pass
            return False

