function setupManualPointDrawing(altitude) {
  let pointId = 1;
  const finishBtn = document.createElement("button");
  finishBtn.textContent = "✅ Завершить расстановку";
  finishBtn.style.position = "absolute";
  finishBtn.style.top = "10px";
  finishBtn.style.right = "10px";
  finishBtn.style.zIndex = 9999;
  document.body.appendChild(finishBtn);
  map.on('click', onClickMapToAddPoint);
  async function onClickMapToAddPoint(e) {
    const lng = e.lngLat.lng;
    const lat = e.lngLat.lat;
    const abs_alt = await getElevationAt(lat, lng);
    generatedPoints.push({ id: pointId, lng, lat, abs_alt, rel_alt: altitude });
    updateGeneratedPointsOnMap();
    pointId++;
  }
  function updateGeneratedPointsOnMap() {
    const features = generatedPoints.map(pt => ({ type: 'Feature', geometry: { type: 'Point', coordinates: [pt.lng, pt.lat] }, properties: { id: pt.id.toString() } }));
    const geojson = { type: 'FeatureCollection', features };
    if (map.getSource(generatedSourceId)) {
      map.getSource(generatedSourceId).setData(geojson);
    } else {
      map.addSource(generatedSourceId, { type: 'geojson', data: geojson });
      map.addLayer({ id: generatedLayerId, type: 'circle', source: generatedSourceId, paint: { 'circle-radius': 5, 'circle-color': '#00ff00' } });
      map.addLayer({ id: generatedLabelLayerId, type: 'symbol', source: generatedSourceId, layout: { 'text-field': ['get', 'id'], 'text-size': 12, 'text-offset': [0, 0.6], 'text-anchor': 'top' }, paint: { 'text-color': '#000000' } });
      setupPointInteractions();
    }
  }
  finishBtn.onclick = () => {
    map.off('click', onClickMapToAddPoint);
    finishBtn.remove();
    updateStatus(`✅ Расстановка завершена. Добавлено ${generatedPoints.length} точек.`);
    if (mapBridge && mapBridge.receiveManualPoints) {
      mapBridge.receiveManualPoints(generatedPoints, altitude);
    }
  };
}
